VALUES
  ('locality-d592fc58-moex-00178', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '依民法規定，下列關於要物契約之敘述，何者錯誤？', '["於契約標的物交付之前，契約當事人得隨時反悔，不成立契約", "要物契約之當事人若未交付標的物，其效果與行使撤銷權相同", "使用借貸契約為要物契約", "寄託契約為要物契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00179', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲、乙訂立A原料10公噸之種類物買賣契約，並約定1個月後給付。數日後，甲將其既有之15 公噸A原料出售，並交付於丙。於甲乙間買賣契約清償日屆至時，甲未能給付約定之標的物於乙。 下列敘述，何者正確？', '["因甲給付不能，乙得請求甲賠償其所受損害", "因甲給付不能，乙得依法催告後解除與甲所締結之契約", "因甲給付遲延，乙不得起訴請求法院判決甲應依約給付", "因甲給付遲延，乙得依法催告後解除契約並請求賠償因此所受損害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00180', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '下列關於債務不履行責任之敘述，何者正確？', '["債權人受領遲延後，因不可歸責於債務人之事由，致標的滅失時，債務人不得向債權人請求對 待給付", "工作未完成前，因承攬人之過失，有違反契約之情事，定作人得定相當期限請求承攬人依約履行", "縱使有可歸責於債務人之嗣後給付不能，債權人不得向債務人請求不履行利益之損害賠償", "倘若債權人依民法第225條第2項規定，於債務人給付不能時，請求債務人給付代償利益，則 債權人不須為對待給付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00181', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '下列關於無主物先占之敘述，何者正確？', '["先占乃屬事實行為，故不以具有法律上之完全行為能力為必要", "先占為一法律行為，得經由代理人代理為之", "無主物先占之客體，得為無主之動產或不動產", "所謂無主物，限於自始無主之物，若為原所有人拋棄之物，則不得對其主張先占"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00182', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '乙偷竊甲所有之名畫，有關甲之損害賠償請求權消滅時效，下列敘述，何者正確？', '["自甲知悉名畫失竊時起，2年間不行使而消滅", "自甲知悉乙偷竊甲之名畫時起，2年間不行使而消滅", "自甲知悉乙偷竊甲之名畫時起，10年間不行使而消滅", "自乙偷竊甲之名畫時起，15年間不行使才消滅 31770 32170"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00183', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲購入屋齡30年之A屋後，因A屋陳舊不堪，而委由乙重新設計裝修。乙完工後，甲入住A屋 時發現，浴室之排水口設置錯誤，無法排水。關於甲乙間之權利義務關係，下列敘述，何者錯誤？', '["甲得定相當期限，請求乙修補，以解決排水問題", "若甲請求乙修補，而乙拒絕修補，甲得請求減少價金", "甲因排水口之瑕疵，而不再信任乙，遂不請求乙修補而自行找第三人修補時，甲得向乙請求償 還修補必要之費用", "甲之瑕疵修補請求權，因瑕疵發見後1年間不行使而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00184', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲、乙、丙三人互約出資購買市區之A房地，以合夥經營商號，並約定由丙執行合夥事務。該商 號嗣後因景氣不佳而負債累累，惟甲、乙個人亦分別積欠丁、戊債務若干尚未償還。下列敘述， 何者錯誤？', '["丁於甲之合夥存續期間內，就甲對於合夥之利益分配請求權，得代位行使之", "戊得聲請扣押乙之股份，乙於扣押實施後兩個月內未向戊清償或提供相當擔保者，自扣押時起 對乙發生退夥之效力", "A房地財產不足清償合夥債務時，甲、乙、丙對於不足之額，連帶負其責任", "執行合夥事務之丙，不須經甲乙兩人之同意，即得任意自行辭任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00185', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '若質權人與出質人未有特別約定時，下列何者非屬動產質權所擔保之債權範圍？', '["遲延利息", "改良質物之費用", "實行質權之費用", "因質物隱有瑕疵而生之損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00186', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲向乙貸款新臺幣（下同）180萬元，以其所有之A屋為乙設定第一次序普通抵押權，甲又向丙 貸款120萬元，以A屋為丙設定第二次序普通抵押權。嗣後，因鄰居丁之過失，致電線走火延燒 而使A屋滅失。下列敘述，何者錯誤？', '["乙對甲之債權，不因A屋滅失而消滅", "乙就甲對丁之賠償債權，有權利質權", "A屋滅失後如留有殘餘物，乙丙對之仍享有抵押權", "乙丙之抵押權均因A屋滅失，隨即消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00187', 'locality-d592fc58', 'locality-d592fc58-moex-111-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '下列何種財產權不得成為時效取得之客體？', '["普通抵押權", "不動產役權", "區分地上權", "普通地上權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL)
